sp_widget.css:
.incident-creator { max-width: 700px; margin: 0 auto; }
.incident-creator .panel-heading { background: #2a6bb6; color: white; font-size: 18px; font-weight: bold; }
.incident-creator .form-group { margin-bottom: 18px; }
.incident-creator label { font-weight: 600; color: #555; margin-bottom: 5px; }
.incident-creator .required::after { content: ' *'; color: #d9534f; }
.incident-creator textarea { resize: vertical; min-height: 100px; }
.incident-creator .btn-primary { background: #2a6bb6; border: none; padding: 10px 30px; font-size: 16px; }
.incident-creator .alert { border-radius: 4px; }
.incident-creator .incident-number { font-size: 18px; font-weight: bold; color: #2a6bb6; }

sp_widget.client_script:
function($scope, spUtil, $timeout) {
    var c = this;
    c.data.category = '';
    c.data.subcategory = '';
    c.data.short_description = '';
    c.data.description = '';
    c.data.urgency = '2';
    c.submitted = false;
    c.error = false;
    c.errorMessage = '';

    // Category options from server
    c.categoryOptions = [];

    // Subcategory mapping
    c.subcategoryOptions = [];
    c.subcategoryMap = {
        'Hardware': ['Laptop', 'Desktop', 'Printer', 'Server', 'Monitor', 'Keyboard', 'Mouse'],
        'Software': ['OS', 'Office', 'ERP', 'CRM', 'Email'],
        'Network': ['Router', 'Switch', 'Firewall', 'VPN', 'WiFi'],
        'Others': ['General', 'Account', 'Inquiry', 'Password']
    };

    // Watch category change
    $scope.$watch(function() { return c.data.category; }, function(newVal) {
        c.data.subcategory = '';
        c.subcategoryOptions = c.subcategoryMap[newVal] || [];
    });

    $scope.submitIncident = function(form) {
        if (!form || form.$invalid) return;
        c.server.get({ action: 'create', 
            category: c.data.category,
            subcategory: c.data.subcategory,
            short_description: c.data.short_description,
            description: c.data.description,
            urgency: c.data.urgency
        }).then(function(r) {
            if (r.data.success) {
                c.submitted = true;
                c.data.incident_number = r.data.number;
                c.data.incident_sys_id = r.data.sys_id;
            } else {
                c.error = true;
                c.errorMessage = r.data.error || 'Failed to create incident';
            }
        });
    };

    $scope.resetForm = function(form) {
        c.data.category = '';
        c.data.subcategory = '';
        c.data.short_description = '';
        c.data.description = '';
        c.data.urgency = '2';
        c.submitted = false;
        c.error = false;
        if (form) { form.$setPristine(); form.$setUntouched(); }
    };
}

sp_widget.server_script:
(function(params) {
    var options = {};

    if (params && params.action === 'create') {
        var gr = new GlideRecord('incident');
        gr.initialize();
        gr.short_description = params.short_description || 'No description';
        gr.description = params.description || '';
        gr.category = params.category || 'Others';
        gr.subcategory = params.subcategory || '';
        gr.urgency = params.urgency || '2';
        gr.impact = params.urgency || '2';
        gr.contact_type = 'self-service';
        gr.caller_id = gs.getUserID();
        var sysId = gr.insert();
        if (sysId) {
            options.success = true;
            options.number = gr.number;
            options.sys_id = sysId;
        } else {
            options.success = false;
            options.error = 'Failed to create incident';
        }
    } else {
        options.categories = ['Hardware', 'Software', 'Network', 'Others'];
    }
    return options;
})(params);

sp_widget.css:
.my-group-incidents table { margin-bottom: 0; }
.my-group-incidents .table-header { background: #f5f5f5; font-weight: bold; }
.my-group-incidents .badge-new { background: #d9534f; }
.my-group-incidents .badge-progress { background: #f0ad4e; }
.my-group-incidents .badge-resolved { background: #5cb85c; }
.my-group-incidents .loading { text-align: center; padding: 40px; color: #999; font-size: 16px; }
.my-group-incidents .no-incidents { text-align: center; padding: 40px; color: #999; }

sp_widget.client_script:
function($scope) {
    var c = this;
    c.data.incidents = [];

    $scope.refresh = function() {
        c.server.get({ action: 'getIncidents' }).then(function(r) {
            c.data.incidents = r.data.incidents || [];
            c.data.groupNames = r.data.groupNames || [];
        });
    };
    $scope.refresh();
}

sp_widget.server_script:
(function(params) {
    if (params && params.action === 'getIncidents') {
        var incidents = [];
        var userGroups = [];
        var grMember = new GlideRecord('sys_user_grmember');
        grMember.addQuery('user', gs.getUserID());
        grMember.query();
        while (grMember.next()) userGroups.push(grMember.getValue('group'));

        var groupNames = [];
        for (var i = 0; i < userGroups.length; i++) {
            var gGr = new GlideRecord('sys_user_group');
            if (gGr.get(userGroups[i])) groupNames.push(gGr.getDisplayValue('name'));
        }

        var gr = new GlideRecord('incident');
        gr.addActiveQuery();
        if (userGroups.length > 0) gr.addQuery('assignment_group', 'IN', userGroups.join(','));
        gr.orderByDesc('sys_created_on');
        gr.setLimit(50);
        gr.query();
        while (gr.next()) {
            incidents.push({
                number: gr.getValue('number'),
                sys_id: gr.getUniqueValue(),
                short_description: gr.getValue('short_description'),
                state: gr.getValue('state'),
                stateDisplay: gr.getDisplayValue('state'),
                priority: gr.getValue('priority'),
                category: gr.getDisplayValue('category'),
                assignment_group: gr.getDisplayValue('assignment_group'),
                assigned_to: gr.getDisplayValue('assigned_to'),
                caller: gr.getDisplayValue('caller_id'),
                created_on: gr.getValue('sys_created_on'),
                escalated: gr.getValue('escalation')
            });
        }
        return { incidents: incidents, groupNames: groupNames };
    }
    return {};
})(params);

sp_widget.css:
.kb-browser .panel-heading { background: #5cb85c; color: white; font-size: 18px; font-weight: bold; }
.kb-browser .article-item { padding: 12px 0; border-bottom: 1px solid #eee; }
.kb-browser .article-item:last-child { border-bottom: none; }
.kb-browser .article-title { font-size: 16px; font-weight: bold; color: #2a6bb6; }
.kb-browser .article-meta { font-size: 12px; color: #999; margin-top: 4px; }
.kb-browser .article-category { display: inline-block; background: #f0f0f0; padding: 2px 8px; border-radius: 3px; font-size: 11px; margin-right: 5px; }
.kb-browser .search-box { margin-bottom: 15px; }

sp_widget.client_script:
function($scope) {
    var c = this;
    c.data.articles = [];
    c.data.knowledgeBases = [];
    c.data.selectedKb = '';
    c.data.searchText = '';

    $scope.search = function() {
        c.server.get({ action: 'search', kb: c.data.selectedKb, search: c.data.searchText }).then(function(r) {
            c.data.articles = r.data.articles || [];
        });
    };

    $scope.viewArticle = function(sysId) {
        window.open('kb_knowledge.do?sys_id=' + sysId, '_blank');
    };

    // Initial load
    c.server.get({ action: 'init' }).then(function(r) {
        c.data.knowledgeBases = r.data.knowledgeBases || [];
        c.data.articles = r.data.articles || [];
    });
}

sp_widget.server_script:
(function(params) {
    var options = {};
    if (params && params.action === 'init') {
        options.knowledgeBases = [];
        var kbGr = new GlideRecord('kb_knowledge_base');
        kbGr.query();
        while (kbGr.next()) {
            options.knowledgeBases.push({
                sys_id: kbGr.getUniqueValue(),
                name: kbGr.getValue('name'),
                title: kbGr.getValue('title')
            });
        }
        options.articles = getArticles();
    } else if (params && params.action === 'search') {
        options.articles = getArticles(params.kb, params.search);
    }
    function getArticles(kbSysId, searchText) {
        var articles = [];
        var gr = new GlideRecord('kb_knowledge');
        gr.addQuery('workflow_state', 'published');
        if (kbSysId) gr.addQuery('kb_knowledge_base', kbSysId);
        if (searchText) {
            var encoded = 'short_descriptionLIKE' + searchText + '^ORtextLIKE' + searchText;
            gr.addEncodedQuery(encoded);
        }
        gr.orderByDesc('sys_created_on');
        gr.setLimit(20);
        gr.query();
        while (gr.next()) {
            articles.push({
                sys_id: gr.getUniqueValue(),
                number: gr.getValue('number'),
                short_description: gr.getValue('short_description'),
                kb_name: gr.getDisplayValue('kb_knowledge_base'),
                category: gr.getDisplayValue('kb_category'),
                author: gr.getDisplayValue('author'),
                created_on: gr.getValue('sys_created_on'),
                snippet: gr.getValue('short_description')
            });
        }
        return articles;
    }
    return options;
})(params);
